import{_ as a,o as n,c as e,a2 as l}from"./chunks/framework.DH0WjybD.js";const u=JSON.parse('{"title":"TypeScript 基础（前端）","description":"","frontmatter":{},"headers":[],"relativePath":"knowledge/vue3-typescript.md","filePath":"knowledge/vue3-typescript.md","lastUpdated":null}'),p={name:"knowledge/vue3-typescript.md"};function o(r,s,i,t,c,d){return n(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="typescript-基础-前端" tabindex="-1">TypeScript 基础（前端） <a class="header-anchor" href="#typescript-基础-前端" aria-label="Permalink to &quot;TypeScript 基础（前端）&quot;">​</a></h1><h2 id="知识简介" tabindex="-1">知识简介 <a class="header-anchor" href="#知识简介" aria-label="Permalink to &quot;知识简介&quot;">​</a></h2><p>TypeScript 是 JavaScript 的超集，添加了静态类型系统。在前端项目中，TypeScript 帮助在编译阶段发现类型错误，提高代码质量和可维护性。jinzhuan-project-web 项目全面使用 TypeScript。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><ul><li><strong>类型注解</strong>：<code>: string</code>、<code>: number</code>、<code>: boolean</code> 等</li><li><strong>接口（interface）</strong>：定义对象的结构</li><li><strong>泛型（Generic）</strong>：<code>&lt;T&gt;</code>，创建可复用的类型</li><li><strong>类型别名（type）</strong>：<code>type User = { name: string }</code></li><li><strong>联合类型</strong>：<code>string | number</code></li><li><strong>可选属性</strong>：<code>name?: string</code></li></ul><h2 id="详细讲解" tabindex="-1">详细讲解 <a class="header-anchor" href="#详细讲解" aria-label="Permalink to &quot;详细讲解&quot;">​</a></h2><p>在 jinzhuan-project-web 项目中，TypeScript 用于：</p><ol><li><strong>接口定义</strong>：定义 API 请求参数、响应数据的结构</li><li><strong>组件类型</strong>：Vue 组件的 props、emits 类型</li><li><strong>类型安全</strong>：避免运行时类型错误</li></ol><p>项目中定义了多个接口来描述请求参数和响应数据：</p><div class="language-typescript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#F97583;">interface</span><span style="color:#B392F0;"> IBindVars</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#FFAB70;">  key</span><span style="color:#F97583;">:</span><span style="color:#79B8FF;"> string</span></span>
<span class="line"><span style="color:#FFAB70;">  value</span><span style="color:#F97583;">:</span><span style="color:#79B8FF;"> string</span><span style="color:#F97583;"> |</span><span style="color:#79B8FF;"> number</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F97583;">interface</span><span style="color:#B392F0;"> IParams</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#FFAB70;">  method</span><span style="color:#F97583;">?:</span><span style="color:#79B8FF;"> string</span></span>
<span class="line"><span style="color:#FFAB70;">  bindVars</span><span style="color:#F97583;">?:</span><span style="color:#B392F0;"> IBindVars</span><span style="color:#E1E4E8;">[]</span></span>
<span class="line"><span style="color:#E1E4E8;">  [key: string]</span><span style="color:#F97583;">:</span><span style="color:#79B8FF;"> any</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>使用 TypeScript 的好处：</p><ul><li>编辑器自动补全和类型提示</li><li>编译时发现类型不匹配错误</li><li>更好的代码文档</li></ul><h2 id="重点内容" tabindex="-1">重点内容 <a class="header-anchor" href="#重点内容" aria-label="Permalink to &quot;重点内容&quot;">​</a></h2><ul><li><code>.ts</code> 文件是 TypeScript 文件，<code>.vue</code> 中使用 <code>&lt;script lang=&quot;ts&quot;&gt;</code></li><li><code>interface</code> 用于定义对象形状，<code>type</code> 更灵活</li><li><code>?</code> 表示可选属性，<code>!</code> 表示非空断言</li><li><code>as</code> 用于类型断言</li><li><code>any</code> 绕过类型检查（应尽量避免）</li></ul><h2 id="关键代码示例" tabindex="-1">关键代码示例 <a class="header-anchor" href="#关键代码示例" aria-label="Permalink to &quot;关键代码示例&quot;">​</a></h2><p>来源：<code>jinzhuan-project-web/src/fetch/index.ts</code></p><div class="language-typescript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;">// 定义 RESTful 参数接口</span></span>
<span class="line"><span style="color:#F97583;">interface</span><span style="color:#B392F0;"> IBindVars</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#FFAB70;">  key</span><span style="color:#F97583;">:</span><span style="color:#79B8FF;"> string</span></span>
<span class="line"><span style="color:#FFAB70;">  value</span><span style="color:#F97583;">:</span><span style="color:#79B8FF;"> string</span><span style="color:#F97583;"> |</span><span style="color:#79B8FF;"> number</span></span>
<span class="line"><span style="color:#E1E4E8;">  [key: string]</span><span style="color:#F97583;">:</span><span style="color:#79B8FF;"> any</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">// 定义请求参数类型</span></span>
<span class="line"><span style="color:#F97583;">interface</span><span style="color:#B392F0;"> IParams</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#FFAB70;">  method</span><span style="color:#F97583;">?:</span><span style="color:#79B8FF;"> string</span></span>
<span class="line"><span style="color:#FFAB70;">  bindVars</span><span style="color:#F97583;">?:</span><span style="color:#B392F0;"> IBindVars</span><span style="color:#E1E4E8;">[]</span></span>
<span class="line"><span style="color:#E1E4E8;">  [key: string]</span><span style="color:#F97583;">:</span><span style="color:#79B8FF;"> any</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">// 扩展 axios 配置类型</span></span>
<span class="line"><span style="color:#F97583;">interface</span><span style="color:#B392F0;"> AxiosRequestProps</span><span style="color:#F97583;"> extends</span><span style="color:#B392F0;"> AxiosRequestConfig</span><span style="color:#E1E4E8;"> {</span></span>
<span class="line"><span style="color:#FFAB70;">  params</span><span style="color:#F97583;">?:</span><span style="color:#B392F0;"> IParams</span></span>
<span class="line"><span style="color:#E1E4E8;">  [key: string]</span><span style="color:#F97583;">:</span><span style="color:#79B8FF;"> any</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h2 id="实际应用场景" tabindex="-1">实际应用场景 <a class="header-anchor" href="#实际应用场景" aria-label="Permalink to &quot;实际应用场景&quot;">​</a></h2><ul><li>API 请求参数和响应数据的类型约束</li><li>Vue 组件的 props 和 emits 类型定义</li><li>Pinia store 的 state 类型定义</li><li>工具函数的参数和返回值类型</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>TypeScript 类型在编译后会被移除，不影响运行时</li><li><code>any</code> 会失去类型检查，应尽量避免使用</li><li>使用 <code>interface</code> 优于 <code>type</code> 定义对象类型（更清晰的错误提示）</li><li><code>tsconfig.json</code> 中的 <code>strict: true</code> 开启严格模式</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><ul><li>误区：过度使用 <code>any</code> 导致 TypeScript 失去意义</li><li>误区：所有变量都需要显式类型注解（TypeScript 可以自动推断）</li><li>误区：<code>interface</code> 和 <code>type</code> 完全相同（interface 可被合并，type 不行）</li></ul><h2 id="关联知识点" tabindex="-1">关联知识点 <a class="header-anchor" href="#关联知识点" aria-label="Permalink to &quot;关联知识点&quot;">​</a></h2><ul><li><a href="/frontend-knowledge-base/knowledge/vue3-composition-api.html">Vue 3 Composition API</a></li><li><a href="/frontend-knowledge-base/knowledge/pinia.html">Pinia 状态管理</a></li><li><a href="/frontend-knowledge-base/knowledge/vite.html">Vite 构建工具</a></li></ul><h2 id="资料来源" tabindex="-1">资料来源 <a class="header-anchor" href="#资料来源" aria-label="Permalink to &quot;资料来源&quot;">​</a></h2><ul><li>来源项目：<code>新前端资源/jinzhuan-project-web/</code></li><li>来源文件：<code>src/fetch/index.ts</code>（接口定义、类型扩展）</li><li>来源文件：<code>src/hooks/interface.ts</code>（类型定义）</li><li>来源文件：<code>src/store/interface.ts</code>（状态类型定义）</li><li>来源文件：<code>tsconfig.json</code>（TypeScript 配置）</li></ul><h2 id="官方资源扩展" tabindex="-1">官方资源扩展 <a class="header-anchor" href="#官方资源扩展" aria-label="Permalink to &quot;官方资源扩展&quot;">​</a></h2><ul><li><a href="https://www.typescriptlang.org/zh/docs/" target="_blank" rel="noreferrer">TypeScript 官方文档</a></li><li>TypeScript 官方中文文档，从基础到高级全覆盖</li><li><a href="https://ts.xcatliu.com/" target="_blank" rel="noreferrer">TypeScript 入门教程</a></li><li>适合初学者的 TypeScript 中文教程</li></ul>`,29)])])}const b=a(p,[["render",o]]);export{u as __pageData,b as default};
